using Microsoft.EntityFrameworkCore;
using System.Linq;

class CosmosQuery
{
    async Task FindProducts(ProductContext ctx)
    {
        // Direct Cosmos SQL — still works because we configured HasDiscriminator("Discriminator")
        // to preserve the old property name. Without that config, EF Core 9 would write "$type"
        // and this query would silently return zero results.
        var sql = "SELECT * FROM c WHERE c.Discriminator = 'Product' AND c.Sku = @sku";

        // EF Core 9 Cosmos provider no longer supports sync I/O (ToList, SaveChanges, etc.).
        // All calls must use async equivalents.
        var products = await ctx.Products.Where(p => p.Sku == "ABC").ToListAsync();
    }
}

